# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.

Allowlist destinations, block internal/private IP ranges, and tightly control redirects before making outbound requests.
# Category: ssrf

defmodule WebhookProxyWeb.ContentController do
  use WebhookProxyWeb, :controller

  plug :allowlisted_destination
  plug :block_internal_ips
  plug :control_redirects

  def fetch_content(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: status_code, body: body}}
        when status_code in [200, 301, 302] ->
          conn
          |> put_status(status_code)
          |> json(%{"content" => body})
        _ ->
          conn
          |> put_status(500)
          |> json(%{"error" => "Failed to fetch content"})
    end
  end

  defp allowlisted_destination(conn, _) do
    allowed_hosts = ["example.com", "another-example.com"]
    url = conn.params["url"]

    if url && URI.parse(url).host in allowed_hosts do
      conn
    else
      conn
      |> put_status(403)
      |> json(%{"error" => "Access denied"})
      |> halt()
    end
  end

  defp block_internal_ips(conn, _) do
    internal_ip_ranges = [
      {"10.0.0.0", "10.255.255.255"},
      {"172.16.0.0", "172.31.255.255"},
      {"192.168.0.0", "192.168.255.255"}
    ]

    url = conn.params["url"]

    if url && Enum.any?(internal_ip_ranges, fn {start, end} -> 
      ip = URI.parse(url).host
      start_int = :inet.parse_address!(start) |> :inet.ntoa() |> String.to_integer()
      end_int = :inet.parse_address!(end) |> :inet.ntoa() |> String.to_integer()
      ip_int = :inet.parse_address!(ip) |> :inet.ntoa() |> String.to_integer()

      ip_int >= start_int and ip_int <= end_int
    end) do
      conn
      |> put_status(403)
      |> json(%{"error" => "Access denied"})
      |> halt()
    else
      conn
    end
  end

  defp control_redirects(conn, _) do
    conn.assign(:redirect_count, 0)
    conn
  end

  defp follow_redirects(conn) do
    url = conn.params["url"]
    redirect_count = conn.assigns.redirect_count

    if redirect_count < 5 do
      case HTTPoison.get(url) do
        {:ok, %HTTPoison.Response{status_code: status_code, headers: headers}}
          when status_code in [301, 302] ->
            location_header = Enum.find(headers, fn {key, _} -> key == "Location" end)
            new_url = location_header && elem(location_header, 1)

            if new_url do
              conn
              |> assign(:redirect_count, redirect_count + 1)
              |> follow_redirects()
            else
              conn
              |> put_status(500)
              |> json(%{"error" => "Invalid redirect"})
            end
          _ ->
            conn
      end
    else
      conn
      |> put_status(403)
      |> json(%{"error" => "Too many redirects"})
    end
  end
end